<template><div class="grid"><section class="galaxy-card span12"><div class="page-title"><h3 class="section-title">帮助中心</h3><el-input v-model="kw" placeholder="搜索问题" style="width:280px" clearable /></div><el-row :gutter="16"><el-col :span="8" v-for="a in filtered" :key="a.id"><div class="script-card"><el-tag>{{a.category}}</el-tag><h3>{{a.title}}</h3><p class="muted">{{a.content}}</p></div></el-col></el-row></section><section class="galaxy-card span12"><h3 class="section-title">高级用户 API</h3><table class="neon-table"><thead><tr><th>服务</th><th>接口</th><th>功能</th></tr></thead><tbody><tr><td>主后端 8081</td><td>/api/auth, /api/voices</td><td>登录注册、声音库管理</td></tr><tr><td>语音AI 8082</td><td>/api/audio, /api/tts, /api/voice</td><td>上传、训练、TTS</td></tr><tr><td>拓展 8083</td><td>/api/scripts, /api/feedback, /api/stats, /api/help</td><td>脚本、评价、统计、帮助</td></tr></tbody></table></section></div></template>
<script setup>import { ref,computed,onMounted } from 'vue';import { getHelpArticles } from '@/api/help';const kw=ref(''),articles=ref([]);onMounted(async()=>{articles.value=await getHelpArticles()});const filtered=computed(()=>articles.value.filter(a=>(a.title+a.content+a.category).includes(kw.value)))</script>
